"use client";

import Link from "next/link";
import { useState } from "react";
import {
  Menu,
    X,
      ChevronDown,
        Heart,
          Stethoscope,
            Pill,
              Baby,
                Activity,
                  ShoppingBag,
                    Video,
                      MessageCircle,
                        Home as HomeIcon,
                          Crown,
                            Star,
                              Users,
                                Sparkles,
                                } from "lucide-react";

                                export default function Navbar() {
                                  const [mobileOpen, setMobileOpen] = useState(false);
                                    const [openDropdown, setOpenDropdown] = useState(null);

                                      const toggleDropdown = (name) => {
                                          setOpenDropdown(openDropdown === name ? null : name);
                                            };

                                              const toolsMenu = [
                                                  { name: "AI Health Assistant", href: "/tools/ai-assistant", icon: Sparkles, desc: "Ask symptoms, get guidance" },
                                                      { name: "Medication Reminder", href: "/tools/medication-tracker", icon: Pill, desc: "Track doses & schedules" },
                                                          { name: "Health Tracker", href: "/tools/health-tracker", icon: Activity, desc: "BP, sugar, weight, water" },
                                                              { name: "Pregnancy Companion", href: "/tools/pregnancy-companion", icon: Baby, desc: "Week-by-week support" },
                                                                  { name: "Kick Counter", href: "/tools/kick-counter", icon: Heart, desc: "Monitor baby movements" },
                                                                    ];

                                                                      const consultMenu = [
                                                                          { name: "Book a Consultation", href: "/consult/book", icon: Video, desc: "Schedule a session" },
                                                                              { name: "Video Consult (30 min)", href: "/consult#video", icon: Video, desc: "₦5,000" },
                                                                                  { name: "Quick Chat Consult", href: "/consult#chat", icon: MessageCircle, desc: "₦2,500 — 24hr reply" },
                                                                                      { name: "Home Visit (Lagos)", href: "/consult#home", icon: HomeIcon, desc: "From 25,000" },
                                                                                          { name: "Second Opinion", href: "/consult#second-opinion", icon: Stethoscope, desc: "₦7,500" },
                                                                                            ];

                                                                                              const premiumMenu = [
                                                                                                  { name: "Join Premium", href: "/premium", icon: Crown, desc: "Start your membership" },
                                                                                                      { name: "Basic Plan — ₦3,500/mo", href: "/premium#basic", icon: Star, desc: "For individuals" },    { name: "Family Plan — ₦7,500/mo", href: "/premium#family", icon: Users, desc: "Up to 4 members" },
                                                                                                          { name: "Annual Plan — 35,000/yr", href: "/premium#annual", icon: Crown, desc: "Save 2 months" },
                                                                                                              { name: "Premium Consultations", href: "/premium#consults", icon: Video, desc: "Priority booking" },
                                                                                                                ];

                                                                                                                  const devicesMenu = [
                                                                                                                      { name: "Blood Pressure Monitors", href: "/medical-devices/bp-monitors", icon: Activity },
                                                                                                                          { name: "Glucose Meters", href: "/medical-devices/glucose-meters", icon: Pill },
                                                                                                                              { name: "Thermometers", href: "/medical-devices/thermometers", icon: Activity },
                                                                                                                                  { name: "Pulse Oximeters", href: "/medical-devices/pulse-oximeters", icon: Activity },
                                                                                                                                      { name: "Nebulizers", href: "/medical-devices/nebulizers", icon: Activity },
                                                                                                                                          { name: "First Aid Kits", href: "/medical-devices/first-aid", icon: Heart },
                                                                                                                                              { name: "Pregnancy & Baby Care", href: "/medical-devices/pregnancy-baby", icon: Baby },
                                                                                                                                                  { name: "Wellness Devices", href: "/medical-devices/wellness", icon: Star },
                                                                                                                                                    ];

                                                                                                                                                      const DropdownItem = ({ item }) => {
                                                                                                                                                          const Icon = item.icon;
                                                                                                                                                              return (
                                                                                                                                                                    <Link
                                                                                                                                                                            href={item.href}
                                                                                                                                                                                    className="flex items-start gap-3 px-4 py-3 hover:bg-emerald-50 transition rounded-lg"
                                                                                                                                                                                            onClick={() => { setOpenDropdown(null); setMobileOpen(false); }}
                                                                                                                                                                                                  >
                                                                                                                                                                                                          {Icon && <Icon className="w-5 h-5 text-emerald-600 mt-0.5 flex-shrink-0" />}
                                                                                                                                                                                                                  <div className="flex-1">
                                                                                                                                                                                                                            <div className="font-medium text-gray-900 text-sm">{item.name}</div>
                                                                                                                                                                                                                                      {item.desc && <div className="text-xs text-gray-500 mt-0.5">{item.desc}</div>}
                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                    </Link>
                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                          };

                                                                                                                                                                                                                                                            const Dropdown = ({ name, items, icon: Icon }) => (
                                                                                                                                                                                                                                                                <div className="relative">
                                                                                                                                                                                                                                                                      <button
                                                                                                                                                                                                                                                                              onClick={() => toggleDropdown(name)}
                                                                                                                                                                                                                                                                                      className="flex items-center gap-1 px-3 py-2 text-gray-700 hover:text-emerald-600 font-medium transition text-sm"
                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                    {name}
                                                                                                                                                                                                                                                                                                            <ChevronDown className={`w-4 h-4 transition-transform ${openDropdown === name ? "rotate-180" : ""}`} />
                                                                                                                                                                                                                                                                                                                  </button>

                                                                                                                                                                                                                                                                                                                        {openDropdown === name && (
                                                                                                                                                                                                                                                                                                                                <>
                                                                                                                                                                                                                                                                                                                                          <div className="fixed inset-0 z-40" onClick={() => setOpenDropdown(null)} />
                                                                                                                                                                                                                                                                                                                                                    <div className="absolute top-full right-0 mt-2 w-80 bg-white rounded-xl shadow-xl border border-gray-100 z-50 py-2 max-h-[80vh] overflow-y-auto">
                                                                                                                                                                                                                                                                                                                                                                <div className="px-4 py-2 border-b border-gray-100 mb-1">
                                                                                                                                                                                                                                                                                                                                                                              <div className="flex items-center gap-2 text-emerald-600 font-semibold text-sm">
                                                                                                                                                                                                                                                                                                                                                                                              <Icon className="w-4 h-4" />                {name}
                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                    {items.map((item) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                  <DropdownItem key={item.name} item={item} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <nav className="sticky top-0 z-50 bg-white/95 backdrop-blur border-b border-gray-100 shadow-sm">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="max-w-7xl mx-auto px-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="flex items-center justify-between h-16">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <Link href="/" className="flex items-center gap-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="w-9 h-9 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-lg flex items-center justify-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Heart className="w-5 h-5 text-white fill-white" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="font-bold text-gray-900 leading-none">CareWell</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="text-xs text-emerald-600 leading-none mt-0.5">Connect</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </Link>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="hidden lg:flex items-center gap-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Link href="/" className="px-3 py-2 text-gray-700 hover:text-emerald-600 font-medium transition text-sm">Home</Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <Link href="/about" className="px-3 py-2 text-gray-700 hover:text-emerald-600 font-medium transition text-sm">About</Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <Dropdown name="Tools" items={toolsMenu} icon={Sparkles} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <Dropdown name="Consult" items={consultMenu} icon={Stethoscope} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Dropdown name="Premium" items={premiumMenu} icon={Crown} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <Dropdown name="Medical Devices" items={devicesMenu} icon={ShoppingBag} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <Link href="/blog" className="px-3 py-2 text-gray-700 hover:text-emerald-600 font-medium transition text-sm">Blog</Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <Link href="/contact" className="px-3 py-2 text-gray-700 hover:text-emerald-600 font-medium transition text-sm">Contact</Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Link href="/premium" className="ml-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg font-medium text-sm transition shadow-sm">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  Join Premium
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              className="lg:hidden p-2 text-gray-700"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          onClick={() => setMobileOpen(!mobileOpen)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {mobileOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {mobileOpen && (        <div className="lg:hidden border-t border-gray-100 bg-white max-h-[calc(100vh-4rem)] overflow-y-auto">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="px-4 py-2 space-y-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <MobileLink href="/" onClick={() => setMobileOpen(false)}>Home</MobileLink>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <MobileLink href="/about" onClick={() => setMobileOpen(false)}>About</MobileLink>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <MobileDropdown name="Tools" items={toolsMenu} icon={Sparkles} openDropdown={openDropdown} toggleDropdown={toggleDropdown} close={() => setMobileOpen(false)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <MobileDropdown name="Consult" items={consultMenu} icon={Stethoscope} openDropdown={openDropdown} toggleDropdown={toggleDropdown} close={() => setMobileOpen(false)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <MobileDropdown name="Premium" items={premiumMenu} icon={Crown} openDropdown={openDropdown} toggleDropdown={toggleDropdown} close={() => setMobileOpen(false)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <MobileDropdown name="Medical Devices" items={devicesMenu} icon={ShoppingBag} openDropdown={openDropdown} toggleDropdown={toggleDropdown} close={() => setMobileOpen(false)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <MobileLink href="/blog" onClick={() => setMobileOpen(false)}>Blog</MobileLink>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <MobileLink href="/contact" onClick={() => setMobileOpen(false)}>Contact</MobileLink>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Link href="/premium" onClick={() => setMobileOpen(false)} className="block text-center px-4 py-3 bg-emerald-600 text-white rounded-lg font-medium mt-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  Join Premium
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </nav>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            function MobileLink({ href, onClick, children }) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Link href={href} onClick={onClick} className="block px-3 py-2 text-gray-700 font-medium hover:bg-emerald-50 rounded-lg">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {children}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              function MobileDropdown({ name, items, icon: Icon, openDropdown, toggleDropdown, close }) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const isOpen = openDropdown === name;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onClick={() => toggleDropdown(name)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            className="flex items-center justify-between w-full px-3 py-2 text-gray-700 font-medium hover:bg-emerald-50 rounded-lg"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className="flex items-center gap-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <Icon className="w-4 h-4 text-emerald-600" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {name}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <ChevronDown className={`w-4 h-4 transition-transform ${isOpen ? "rotate-180" : ""}`} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {isOpen && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="ml-4 mt-1 space-y-1 border-l-2 border-emerald-100 pl-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {items.map((item) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const ItemIcon = item.icon;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Link
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  key={item.name}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  href={item.href}                onClick={close}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className="flex items-center gap-2 px-3 py-2 text-sm text-gray-600 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {ItemIcon && <ItemIcon className="w-4 h-4" />}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <span>{item.name}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    })}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }